import{_ as n,c as t,o as i,a1 as s}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Kernfunktionen: Drei Hauptfähigkeiten | opencode-dcp","description":"Lernen Sie die drei Kernfunktionen von opencode-dcp: automatische Beschneidungsstrategien, LLM-gesteuerte Tools und Slash-Befehle. Nutzen Sie diese Funktionen vollständig zur Token-Optimierung.","frontmatter":{"title":"Kernfunktionen: Drei Hauptfähigkeiten | opencode-dcp","sidebarTitle":"Drei Hauptfähigkeiten freischalten","subtitle":"Kernfunktionen: Drei Hauptfähigkeiten","description":"Lernen Sie die drei Kernfunktionen von opencode-dcp: automatische Beschneidungsstrategien, LLM-gesteuerte Tools und Slash-Befehle. Nutzen Sie diese Funktionen vollständig zur Token-Optimierung.","order":20},"headers":[],"relativePath":"de/Opencode-DCP/opencode-dynamic-context-pruning/platforms/index.md","filePath":"de/Opencode-DCP/opencode-dynamic-context-pruning/platforms/index.md"}'),a={name:"de/Opencode-DCP/opencode-dynamic-context-pruning/platforms/index.md"};function r(o,e,d,l,h,u){return i(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="kernfunktionen" tabindex="-1">Kernfunktionen <a class="header-anchor" href="#kernfunktionen" aria-label="Permalink to &quot;Kernfunktionen&quot;">​</a></h1><p>In diesem Kapitel werden die drei Kernfähigkeiten von DCP eingehend erläutert: automatische Beschneidungsstrategien, LLM-gesteuerte Tools und Slash-Befehle. Nachdem Sie diese Funktionen beherrschen, können Sie das Token-Optimierungspotenzial von DCP voll ausschöpfen.</p><h2 id="kapitelinhalt" tabindex="-1">Kapitelinhalt <a class="header-anchor" href="#kapitelinhalt" aria-label="Permalink to &quot;Kapitelinhalt&quot;">​</a></h2><div class="grid-cards"><h3 id="automatische-beschneidungsstrategien" tabindex="-1"><a href="./auto-pruning/">Automatische Beschneidungsstrategien</a> <a class="header-anchor" href="#automatische-beschneidungsstrategien" aria-label="Permalink to &quot;[Automatische Beschneidungsstrategien](./auto-pruning/)&quot;">​</a></h3><p>Verstehen Sie im Detail, wie die drei automatischen Strategien von DCP funktionieren: Deduplizierungsstrategie, Überschreibungsstrategie und Fehlerbereinigungsstrategie. Erfahren Sie die Auslösebedingungen und Anwendungsszenarien für jede Strategie.</p><h3 id="llm-gesteuerte-beschneidungstools" tabindex="-1"><a href="./llm-tools/">LLM-gesteuerte Beschneidungstools</a> <a class="header-anchor" href="#llm-gesteuerte-beschneidungstools" aria-label="Permalink to &quot;[LLM-gesteuerte Beschneidungstools](./llm-tools/)&quot;">​</a></h3><p>Verstehen Sie, wie KI autonom die Tools <code>discard</code> und <code>extract</code> aufruft, um den Kontext zu optimieren. Dies ist die intelligenteste Funktion von DCP, bei der KI aktiv an der Kontextverwaltung teilnimmt.</p><h3 id="slash-befehle-verwenden" tabindex="-1"><a href="./commands/">Slash-Befehle verwenden</a> <a class="header-anchor" href="#slash-befehle-verwenden" aria-label="Permalink to &quot;[Slash-Befehle verwenden](./commands/)&quot;">​</a></h3><p>Beherrschen Sie die Verwendung aller DCP-Befehle: <code>/dcp context</code> zum Anzeigen des Kontextstatus, <code>/dcp stats</code> zum Anzeigen von Statistiken, <code>/dcp sweep</code> zum manuellen Auslösen der Beschneidung.</p></div><h2 id="lernpfad" tabindex="-1">Lernpfad <a class="header-anchor" href="#lernpfad" aria-label="Permalink to &quot;Lernpfad&quot;">​</a></h2><p>Es wird empfohlen, den Inhalt dieses Kapitels in der folgenden Reihenfolge zu lernen:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Automatische Beschneidungsstrategien → LLM-gesteuerte Tools → Slash-Befehle</span></span>
<span class="line"><span>              ↓                              ↓                       ↓</span></span>
<span class="line"><span>        Prinzipien verstehen          Intelligente Beschneidung   Überwachung und</span></span>
<span class="line"><span>                                             beherrschen          Debugging lernen</span></span></code></pre></div><ol><li><strong>Beginnen Sie mit automatischen Beschneidungsstrategien</strong>: Dies ist die Grundlage von DCP. Verstehen Sie die Funktionsweise der drei Strategien.</li><li><strong>Lernen Sie dann LLM-gesteuerte Tools</strong>: Nachdem Sie die automatischen Strategien verstanden haben, lernen Sie die fortschrittlicheren KI-aktiven Beschneidungsfähigkeiten.</li><li><strong>Lernen Sie abschließend Slash-Befehle</strong>: Beherrschen Sie die Methoden zur Überwachung und manuellen Steuerung, um Debugging und Optimierung zu erleichtern.</li></ol><div class="tip custom-block"><p class="custom-block-title">Voraussetzungen</p><p>Bevor Sie dieses Kapitel lernen, stellen Sie sicher, dass Sie Folgendes abgeschlossen haben:</p><ul><li><a href="./../start/getting-started/">Installation und Schnellstart</a> - Installation des DCP-Plugins abgeschlossen</li><li><a href="./../start/configuration/">Komplette Konfiguration</a> - Grundlegende Konzepte des Konfigurationssystems verstanden</li></ul></div><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Kapitels können Sie weiter erkunden:</p><ul><li><strong><a href="./../advanced/protection/">Schutzmechanismen</a></strong> - Lernen Sie, wie Sie wichtige Inhalte vor versehentlicher Beschneidung schützen</li><li><strong><a href="./../advanced/state-persistence/">Status-Persistenz</a></strong> - Erfahren Sie, wie DCP den Status über Sitzungen hinweg beibehält</li><li><strong><a href="./../advanced/prompt-caching/">Prompt-Caching-Auswirkungen</a></strong> - Verstehen Sie die Abwägungen zwischen DCP und Prompt Caching</li></ul>`,12)])])}const p=n(a,[["render",r]]);export{g as __pageData,p as default};
